#!/bin/bash
# context-reset.sh - Handle context reset events (/clear, /compact)
# Generated by /s2s:init
# Version: 2.1.0
#
# Hook for SessionStart event - detects context resets.
#
# Behavior:
#   - Updates state.json with last_activity (requires jq)
#   - Shows resume command if roundtable was interrupted
#
# Dependencies:
#   - jq (recommended): Full functionality including state.json updates
#   - Without jq: Core functionality works, state.json update skipped
#
# Configuration:
#   Add to .claude/settings.json:
#   {
#     "hooks": {
#       "SessionStart": [{
#         "hooks": [{
#           "type": "command",
#           "command": ".claude/context-reset.sh"
#         }]
#       }]
#     }
#   }

INPUT=$(cat)

# Check jq availability
if command -v jq &>/dev/null; then
    HAS_JQ=true
else
    HAS_JQ=false
fi

# Helper: extract value from flat JSON using grep/sed (fallback when no jq)
# Usage: json_extract "key" "$json_string"
json_extract() {
    local key="$1"
    local json="$2"
    echo "$json" | grep -o "\"${key}\":\"[^\"]*\"" | head -1 | cut -d'"' -f4
}

# Helper: extract value from file using grep (fallback when no jq)
# Usage: json_extract_file "key" "/path/to/file.json"
json_extract_file() {
    local key="$1"
    local file="$2"
    grep -o "\"${key}\":\"[^\"]*\"" "$file" 2>/dev/null | head -1 | cut -d'"' -f4
}

# Helper: extract number from file using grep (fallback when no jq)
# Usage: json_extract_number_file "key" "/path/to/file.json"
json_extract_number_file() {
    local key="$1"
    local file="$2"
    grep -o "\"${key}\":[0-9]*" "$file" 2>/dev/null | head -1 | sed 's/.*://'
}

# Get project directory from input
if [[ "$HAS_JQ" == "true" ]]; then
    PROJECT_DIR=$(echo "$INPUT" | jq -r '.cwd // "."')
else
    PROJECT_DIR=$(json_extract "cwd" "$INPUT")
    PROJECT_DIR=${PROJECT_DIR:-.}
fi

S2S_DIR="${PROJECT_DIR}/.s2s"
STATE_FILE="${S2S_DIR}/state.json"

# Check if this is an s2s project
[[ ! -d "$S2S_DIR" ]] && exit 0
[[ ! -f "$STATE_FILE" ]] && exit 0

# Parse event source
if [[ "$HAS_JQ" == "true" ]]; then
    SOURCE=$(echo "$INPUT" | jq -r '.source // "startup"')
else
    SOURCE=$(json_extract "source" "$INPUT")
    SOURCE=${SOURCE:-startup}
fi

# Only handle clear and compact events
[[ "$SOURCE" != "clear" && "$SOURCE" != "compact" ]] && exit 0

# Get active session info (if any)
if [[ "$HAS_JQ" == "true" ]]; then
    WORKFLOW_TYPE=$(jq -r '.active_session.workflow_type // ""' "$STATE_FILE" 2>/dev/null)
    RT_SESSION_ID=$(jq -r '.active_session.id // ""' "$STATE_FILE" 2>/dev/null)
    RT_ROUND=$(jq -r '.active_session.round // 0' "$STATE_FILE" 2>/dev/null)
else
    WORKFLOW_TYPE=$(json_extract_file "workflow_type" "$STATE_FILE")
    RT_SESSION_ID=$(json_extract_file "id" "$STATE_FILE")
    RT_ROUND=$(json_extract_number_file "round" "$STATE_FILE")
    RT_ROUND=${RT_ROUND:-0}
fi

# Update state.json with last_activity (only if jq available)
if [[ "$HAS_JQ" == "true" ]]; then
    TIMESTAMP=$(date -u +%Y-%m-%dT%H:%M:%SZ)
    jq --arg action "context_${SOURCE}" \
       --arg timestamp "$TIMESTAMP" \
       --arg session_id "$RT_SESSION_ID" \
       '.last_activity = {
         "timestamp": $timestamp,
         "action": $action,
         "session_id": (if $session_id == "" then null else $session_id end)
       }' "$STATE_FILE" > "${STATE_FILE}.tmp" && mv "${STATE_FILE}.tmp" "$STATE_FILE"
fi

# Show resume command if roundtable was active
if [[ -n "$WORKFLOW_TYPE" && -n "$RT_SESSION_ID" ]]; then
    echo ""
    echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
    echo "  Roundtable interrupted by /${SOURCE}"
    echo ""
    echo "    Workflow: ${WORKFLOW_TYPE}"
    echo "    Session:  ${RT_SESSION_ID}"
    echo "    Round:    ${RT_ROUND} completed"
    echo ""
    echo "  To resume:"
    echo "    /s2s:${WORKFLOW_TYPE} --session ${RT_SESSION_ID}"
    echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
    echo ""
fi

# Show warning if jq not available
if [[ "$HAS_JQ" != "true" ]]; then
    echo ""
    echo "  Note: 'jq' not found. Install jq for full functionality."
    echo "    macOS:   brew install jq"
    echo "    Linux:   apt install jq  (or equivalent)"
    echo "    Windows: choco install jq  (or download from https://jqlang.github.io/jq/)"
    echo ""
fi

exit 0
